/* site.min.css — FIRST-CLASS Eleventy template (round-17 Cloudflare CSS fix).
 *
 * WHY THIS FILE EXISTS: site.min.css was previously generated by a side-effect
 * `fs.writeFileSync` inside an `eleventy.before` hook — writing straight to the
 * output dir OUTSIDE Eleventy's own write pipeline. That file is not tracked by
 * Eleventy as build output, which makes it fragile on CI/Cloudflare (it can be
 * absent from the deployed artifact even when HTML deploys). A fresh-clone
 * `npm ci --omit=dev && npm run build` proved the SOURCE + build are correct, so
 * the only remaining failure surface was that non-canonical write. Moving the
 * bundle into a normal Eleventy template makes site.min.css a first-class build
 * output that flows through Eleventy's writer and is always in _site → always
 * deployed by Cloudflare. Page content is untouched; this is build-pipeline only.
 *
 * Bundles the 10 design-handoff CSS sources (foundations verbatim, components
 * curated per round) in load order, minified via esbuild. 58KB minified hard
 * gate (throws if exceeded); 70KB source soft-cap (flagged, non-blocking). */
const fs = require("fs");
const path = require("path");

const CSS_ORDER = [
  "00-fonts.css",
  "01-tokens.css",
  "02-base.css",
  "03-conversion.css",
  "04-chrome.css",
  "05-tiers.css",
  "06-motif-rules.css",
  "07-motion.css",
  "08-additions.css",
  "09-extensions.css",
];
// Re-set for the elevated design system (capture round, 2026-06-16). The cobalt
// floor used 58KB; the elevated library adds the section-layout engine, the 4
// signature diagrams, call-band, mid-mega nav and per-type heroes. New ceiling
// set with headroom; tighten after the full re-skin lands.
// 2026-06-20 (D1 dossier re-skin): the HEAD bundle already sat at 81.5KB —
// the 82KB ceiling left zero headroom for the D1 money-page section-layout
// engine the comment above anticipated (split/feature/asymmetric/zigzag/
// callout/stat-band + dossier ai-summary + cleanup-timeline). Raised to a
// 100KB TRANSITION CEILING (founder ruling 2026-06-20) — the new design is
// layered on while old components still serve 500+ un-converted pages, so the
// bundle grows mid-transition and nets back down as legacy CSS is deleted
// family-by-family. NOT the final budget: the flip-gate carries a hard "CSS
// must net back under target before flip" line; tighten via css_audit.py once
// the per-type re-skin lands. Kept in sync with _build/battery/run_battery.py.
const CSS_BUDGET_MIN = 100 * 1024; // minified, hard build gate (transition ceiling)
const CSS_BUDGET_SRC = 130 * 1024; // source soft-cap, flagged only

module.exports = class {
  data() {
    return {
      permalink: "/assets/css/site.min.css",
      eleventyExcludeFromCollections: true,
    };
  }

  async render() {
    const esbuild = require("esbuild");
    const srcDir = __dirname; // this file lives in src/assets/css alongside the sources
    const source = CSS_ORDER.map((f) =>
      // strip per-file BOMs — a U+FEFF mid-concatenation corrupts the next
      // selector after minification (esbuild escapes it into the selector)
      fs.readFileSync(path.join(srcDir, f), "utf8").replace(/^﻿/, "")
    ).join("\n");
    const srcBytes = Buffer.byteLength(source);
    const { code } = await esbuild.transform(source, {
      loader: "css",
      minify: true,
    });
    const minBytes = Buffer.byteLength(code);
    if (minBytes > CSS_BUDGET_MIN) {
      throw new Error(
        `CSS minified budget exceeded: ${minBytes} > ${CSS_BUDGET_MIN} bytes`
      );
    }
    const srcFlag = srcBytes > CSS_BUDGET_SRC
      ? " ⚠ SOURCE OVER 70KB SOFT-CAP (flagged)" : "";
    console.log(
      `[css] minified ${minBytes}B / hard gate ${CSS_BUDGET_MIN}B · source ${srcBytes}B${srcFlag} → assets/css/site.min.css (first-class template)`
    );
    return code;
  }
};
